// ── Extrai dados do webhook da Evolution API ──────────────
const body = $input.first().json;

// Ignora mensagens do próprio bot e eventos não-mensagem
if (body?.data?.key?.fromMe === true) {
  return [{ json: { action: 'skip', reason: 'fromMe' } }];
}
const event = body?.event || '';
if (!event.includes('messages')) {
  return [{ json: { action: 'skip', reason: 'not_message' } }];
}

// Ignora grupos
const remoteJid = body?.data?.key?.remoteJid || '';
if (remoteJid.includes('@g.us')) {
  return [{ json: { action: 'skip', reason: 'group' } }];
}

const phone = remoteJid.replace(/@s\.whatsapp\.net/, '').replace(/[^0-9]/g, '');
const msgData = body?.data?.message || {};
const text = (
  msgData.conversation ||
  msgData.extendedTextMessage?.text ||
  msgData.imageMessage?.caption ||
  ''
).trim();

const pushName = body?.data?.pushName || 'amigo';

if (!phone || !text) {
  return [{ json: { action: 'skip', reason: 'no_data' } }];
}

// ── Detecta se é transação financeira ─────────────────────
const lower = text.toLowerCase();

const ENTRADA_WORDS = ['entrada', 'recebi', 'salario', 'salário', 'renda', 'ganho', 'ganhei', 'pix recebido'];
const SAIDA_WORDS = ['saida', 'saída', 'gasto', 'gastei', 'paguei', 'pagamento', 'despesa', 'comprei', 'transferi', 'debito', 'débito'];

let kind = null;
for (const w of ENTRADA_WORDS) {
  if (lower.startsWith(w) || lower.includes(' ' + w)) { kind = 'income'; break; }
}
if (!kind) {
  for (const w of SAIDA_WORDS) {
    if (lower.startsWith(w) || lower.includes(' ' + w)) { kind = 'expense'; break; }
  }
}

const amountMatch = text.match(/(\d+[.,]?\d*)/);
const amount = amountMatch ? parseFloat(amountMatch[1].replace(',', '.')) : null;

if (kind && amount && amount > 0) {
  let category = 'Geral';
  if (amountMatch) {
    const after = text.slice(text.indexOf(amountMatch[1]) + amountMatch[1].length).trim();
    if (after.length > 1) category = after.charAt(0).toUpperCase() + after.slice(1);
  }
  return [{ json: { action: 'transaction', phone, pushName, kind, amount, category, description: text } }];
}

// ── Qualquer outra mensagem → Agente IA ───────────────────
return [{ json: { action: 'ai_chat', phone, pushName, text } }];

// ── Extrai resposta do agente IA ──────────────────────────
const aiResp = $input.first().json;
const parsed = $('Parsear Mensagem').first().json;

const reply = aiResp?.reply || 'Olá! Me diga como posso ajudar. Digite *quero* para conhecer o FinanceZap ⚡';

return [{ json: { phone: parsed.phone, msg: reply } }];

// ── Resultado da transação ─────────────────────────────────
const apiResp = $input.first().json;
const parsed = $('Parsear Mensagem').first().json;
const phone = parsed.phone;

if (apiResp.ok) {
  const valor = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(parsed.amount);
  const emoji = parsed.kind === 'income' ? '💚' : '❤️';
  const tipo = parsed.kind === 'income' ? 'Entrada' : 'Saída';
  return [{ json: { phone, msg: `${emoji} *${tipo} registrada!*\n\n💰 Valor: *${valor}*\n🏷️ Categoria: *${parsed.category}*\n\n✅ Salvo no FinanceZap!` } }];
}

if (apiResp.status === 'not_registered') {
  return [{ json: { phone, msg: `⚡ Você ainda não tem conta no *FinanceZap*!\n\nMe manda um *oi* que te explico como funciona 😉` } }];
}

if (apiResp.status === 'no_access') {
  return [{ json: { phone, msg: `⏳ Sua conta existe mas o acesso ainda não foi liberado.\n\nSe já pagou, aguarde a confirmação. Se não, me manda *quero* que te explico!` } }];
}

return [{ json: { phone, msg: `⚠️ Não consegui registrar. Tente novamente em alguns segundos.` } }];
